// TestBooleanEvaluationSuccess tests the boolean evaluation endpoint with a valid request
func TestBooleanEvaluationSuccess(t *testing.T) {
	testStore := setupTestDatabase(t)
	defer testStore.Shutdown(context.Background())

	// Create test data
	ctx := context.Background()
	store, err := storagesql.New(testStore.DB)
	require.NoError(t, err)

	// Create namespace
	_, err = store.CreateNamespace(ctx, &flipt.CreateNamespaceRequest{
		Key: "default",
	})
	require.NoError(t, err)

	// Create boolean flag
	flag, err := store.CreateFlag(ctx, &flipt.CreateFlagRequest{
		NamespaceKey: "default",
		Key:          "feature-enabled",
		Name:         "Feature Enabled",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      true,
	})
	require.NoError(t, err)
	require.NotNil(t, flag)

	// Create evaluation server
	logger := zaptest.NewLogger(t)
	server := evaluation.New(logger, store)

	// Create HTTP server using httptest
	mux := http.NewServeMux()
	registerEvaluationHandlers(mux, server)
	ts := httptest.NewServer(mux)
	defer ts.Close()

	// Make request
	reqBody := rpcevaluation.EvaluationRequest{
		NamespaceKey: "default",
		FlagKey:      "feature-enabled",
		EntityId:     "user-123",
	}
	reqData, err := protojson.Marshal(&reqBody)
	require.NoError(t, err)

	resp, err := http.Post(
		ts.URL+"/evaluate/v1/boolean",
		"application/json",
		bytes.NewReader(reqData),
	)
	require.NoError(t, err)
	require.NotNil(t, resp)
	defer resp.Body.Close()

	// Assert response
	require.Equal(t, http.StatusOK, resp.StatusCode)

	respData, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var respBody rpcevaluation.BooleanEvaluationResponse
	err = protojson.Unmarshal(respData, &respBody)
	require.NoError(t, err)

	assert.True(t, respBody.Enabled)
	assert.Equal(t, "feature-enabled", respBody.FlagKey)
}

// TestVariantEvaluationSuccess tests the variant evaluation endpoint with a valid request
func TestVariantEvaluationSuccess(t *testing.T) {
	testStore := setupTestDatabase(t)
	defer testStore.Shutdown(context.Background())

	ctx := context.Background()
	store, err := storagesql.New(testStore.DB)
	require.NoError(t, err)

	// Create namespace
	_, err = store.CreateNamespace(ctx, &flipt.CreateNamespaceRequest{
		Key: "default",
	})
	require.NoError(t, err)

	// Create variant flag
	flag, err := store.CreateFlag(ctx, &flipt.CreateFlagRequest{
		NamespaceKey: "default",
		Key:          "variant-flag",
		Name:         "Variant Flag",
		Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		Enabled:      true,
	})
	require.NoError(t, err)

	// Create variants
	variant, err := store.CreateVariant(ctx, &flipt.CreateVariantRequest{
		NamespaceKey: "default",
		FlagKey:      "variant-flag",
		Key:          "control",
		Name:         "Control",
		Attachment:   `{"color":"blue"}`,
	})
	require.NoError(t, err)
	require.NotNil(t, variant)

	// Create evaluation server
	logger := zaptest.NewLogger(t)
	server := evaluation.New(logger, store)

	// Create HTTP server
	mux := http.NewServeMux()
	registerEvaluationHandlers(mux, server)
	ts := httptest.NewServer(mux)
	defer ts.Close()

	// Make request
	reqBody := rpcevaluation.EvaluationRequest{
		NamespaceKey: "default",
		FlagKey:      "variant-flag",
		EntityId:     "user-456",
	}
	reqData, err := protojson.Marshal(&reqBody)
	require.NoError(t, err)

	resp, err := http.Post(
		ts.URL+"/evaluate/v1/variant",
		"application/json",
		bytes.NewReader(reqData),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	require.Equal(t, http.StatusOK, resp.StatusCode)

	respData, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var respBody rpcevaluation.VariantEvaluationResponse
	err = protojson.Unmarshal(respData, &respBody)
	require.NoError(t, err)

	assert.Equal(t, "variant-flag", respBody.FlagKey)
	assert.NotEmpty(t, respBody.VariantKey)
}

// TestBooleanEvaluationFlagNotFound tests flag not found behavior (should return error response)
func TestBooleanEvaluationFlagNotFound(t *testing.T) {
	testStore := setupTestDatabase(t)
	defer testStore.Shutdown(context.Background())

	ctx := context.Background()
	store, err := storagesql.New(testStore.DB)
	require.NoError(t, err)

	// Create namespace (but no flag)
	_, err = store.CreateNamespace(ctx, &flipt.CreateNamespaceRequest{
		Key: "default",
	})
	require.NoError(t, err)

	// Create evaluation server
	logger := zaptest.NewLogger(t)
	server := evaluation.New(logger, store)

	// Create HTTP server
	mux := http.NewServeMux()
	registerEvaluationHandlers(mux, server)
	ts := httptest.NewServer(mux)
	defer ts.Close()

	// Make request for non-existent flag
	reqBody := rpcevaluation.EvaluationRequest{
		NamespaceKey: "default",
		FlagKey:      "does-not-exist",
		EntityId:     "user-123",
	}
	reqData, err := protojson.Marshal(&reqBody)
	require.NoError(t, err)

	resp, err := http.Post(
		ts.URL+"/evaluate/v1/boolean",
		"application/json",
