	body2, err := io.ReadAll(resp2.Body)
	require.NoError(t, err)

	var result2 rpcevaluation.BooleanEvaluationResponse
	err = protojson.Unmarshal(body2, &result2)
	require.NoError(t, err)

	// Assert different results for same flag key in different namespaces
	assert.True(t, result1.Enabled)
	assert.False(t, result2.Enabled)
}

