// registerEvaluationHandlers registers the evaluation service handlers to an HTTP mux
func registerEvaluationHandlers(mux *http.ServeMux, server *evaluation.Server) {
	// Boolean evaluation endpoint
	mux.HandleFunc("/evaluate/v1/boolean", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}

		var req rpcevaluation.EvaluationRequest
		body, err := io.ReadAll(r.Body)
		if err != nil {
			http.Error(w, "failed to read request body", http.StatusBadRequest)
			return
		}
		defer r.Body.Close()

		if err := protojson.Unmarshal(body, &req); err != nil {
			http.Error(w, "failed to unmarshal request", http.StatusBadRequest)
			return
		}

		ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
		defer cancel()

		resp, err := server.Boolean(ctx, &req)
		if err != nil {
			http.Error(w, fmt.Sprintf("evaluation error: %v", err), http.StatusInternalServerError)
			return
		}

		respData, err := protojson.Marshal(resp)
		if err != nil {
			http.Error(w, "failed to marshal response", http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write(respData)
	})

	// Variant evaluation endpoint
	mux.HandleFunc("/evaluate/v1/variant", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}

		var req rpcevaluation.EvaluationRequest
		body, err := io.ReadAll(r.Body)
		if err != nil {
			http.Error(w, "failed to read request body", http.StatusBadRequest)
			return
		}
		defer r.Body.Close()

		if err := protojson.Unmarshal(body, &req); err != nil {
			http.Error(w, "failed to unmarshal request", http.StatusBadRequest)
			return
		}

		ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
		defer cancel()

		resp, err := server.Variant(ctx, &req)
		if err != nil {
			http.Error(w, fmt.Sprintf("evaluation error: %v", err), http.StatusInternalServerError)
			return
		}

		respData, err := protojson.Marshal(resp)
		if err != nil {
			http.Error(w, "failed to marshal response", http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write(respData)
	})

	// Batch evaluation endpoint
	mux.HandleFunc("/evaluate/v1/batch", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}

		var req rpcevaluation.BatchEvaluationRequest
		body, err := io.ReadAll(r.Body)
		if err != nil {
			http.Error(w, "failed to read request body", http.StatusBadRequest)
			return
		}
		defer r.Body.Close()

		if err := protojson.Unmarshal(body, &req); err != nil {
			http.Error(w, "failed to unmarshal request", http.StatusBadRequest)
			return
		}

		ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
		defer cancel()

		resp, err := server.Batch(ctx, &req)
		if err != nil {
			http.Error(w, fmt.Sprintf("evaluation error: %v", err), http.StatusInternalServerError)
			return
		}

		// Add timestamps to responses
		for _, evalResp := range resp.Responses {
			switch v := evalResp.Response.(type) {
			case *rpcevaluation.EvaluationResponse_BooleanResponse:
				if v.BooleanResponse.Timestamp == nil {
					v.BooleanResponse.Timestamp = timestamppb.Now()
				}
			case *rpcevaluation.EvaluationResponse_VariantResponse:
				if v.VariantResponse.Timestamp == nil {
					v.VariantResponse.Timestamp = timestamppb.Now()
				}
			}
		}

		respData, err := protojson.Marshal(resp)
		if err != nil {
			http.Error(w, "failed to marshal response", http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write(respData)
	})
}

